dw:transform-message.dw:set-payload:
%dw 2.0 output text/plain fun toHl7Name(last, first, middle) = (last default "PATIENT DECLINED") ++ "^" ++ (first default "PATIENT DECLINED") ++ "^" ++ (middle default "") fun normGender(g) = (g as String {default:""} toUpperCase()) match { case "M" -> "M" case "F" -> "F" else -> "U" } fun normLang(l) = (l default "EN") // Replace with code table if needed --- ( // MSH "MSH|^~\\&|HEALTHFUSION^1266378|NEXTGENOFFICE^1266378|FORESTHMS|FORESTHMS^1266378|" ++ now() as String {format: "yyyyMMddHHmmss"} ++ "||ADT^A04|" ++ (uuid() as String) ++ "|P|2.3" ++ "\n" ++
// PID "PID|1|" ++ (payload.HealthFusion_Patient_Record_ID__c default "") ++ "|" ++ (payload.HealthFusion_Patient_Record_ID__c default "") ++ "|" ++ ("HF" ++ (payload.HealthFusion_Patient_Record_ID__c default "")) ++ "|" ++ toHl7Name(payload.LastName__c, payload.FirstName__c, payload.MiddleName__c) ++ "||" ++ (payload.Date_of_Birth__c default "") ++ "|" ++ normGender(payload.Patient_Gender__c) ++ "||" ++ (payload.Patient_Race__c default "PATIENT DECLINED") ++ "|" ++ (payload.MailingStreet__c default "") ++ "^^" ++ (payload.MailingCity__c default "") ++ "^" ++ (payload.MailingState__c default "") ++ "^" ++ (payload.MailingPostalCode__c default "") ++ "|" ++ "(" ++ (payload.Phone__c default "") ++ ")" ++ (payload.Phone__c default "") ++ "^^^" ++ (payload.Email__c default "") ++ "^^" ++ (payload.Phone__c default "") ++ "^" ++ (payload.PhoneNumberFormatted__c default "") ++ "||" ++ normLang(payload.Language__c) ++ "|||||||" ++ (payload.Patient_Ethnicity__c default "PATIENT DECLINED") ++ "\n" ++
// PV1 (Example/simplified) "PV1|1|O|^^^1275017^^^^^FOREST HILLS||||||||1275017^^^1275017^^^^^FOREST HILLS|||||||||||||||||||||||N|||||1266378;FOREST HILLS MEDICAL SERVICES;FORESTHMS" ++ "\n" ++
// GT1 "GT1|1|" ++ (payload.HealthFusion_Patient_Record_ID__c default "") ++ "|" ++ toHl7Name(payload.LastName__c, payload.FirstName__c, payload.MiddleName__c) ++ "||" ++ (payload.MailingStreet__c default "") ++ "^^" ++ (payload.MailingCity__c default "") ++ "^" ++ (payload.MailingState__c default "") ++ "^" ++ (payload.MailingPostalCode__c default "") ++ "|" ++ "(" ++ (payload.Phone__c default "") ++ ")" ++ (payload.Phone__c default "") ++ "^^^" ++ (payload.Email__c default "") ++ "^^" ++ (payload.Phone__c default "") ++ "^" ++ (payload.PhoneNumberFormatted__c default "") ++ "||" ++ ((payload.Date_of_Birth__c default "") ++ "000000") ++ "|" ++ normGender(payload.Patient_Gender__c) ++ "||OTHER" )
